	let isEscaped = false;

	for (let index = 0; index < text.length; index++) {
		const char = text[index];
		if (!char) {
			continue;
		}

		if (isEscaped) {
			isEscaped = false;
			continue;
		}

		if (char === "\\") {
			isEscaped = true;
			continue;
		}

		if (char === '"') {
			inString = !inString;
			continue;
		}

		if (inString) {
			continue;
		}

		if (char === "{") {
			if (depth === 0) {
				startIndex = index;
			}
			depth++;
			continue;
		}

		if (char === "}") {
			if (depth === 0) {
