			),
		};
	}

	if (type === "persist_work") {
		return {
			type: "persist_work",
		};
	}

	if (type === "persist_qa") {
		return {
			type: "persist_qa",
		};
	}

	throw new Error(
		`actions[${index}].type must be "run_shell", "persist_work", or "persist_qa"`,
	);
